def solve(file_list):
    if not isinstance(file_list, list):
        raise ValueError("Input must be a list of files.")

    if not file_list:
        return []

    loaded_files = []
    for file in file_list:
        if not isinstance(file, str):
            raise ValueError("Each file must be a string representing the file path.")

        # Simulate loading the file based on its extension
        file_extension = file.split('.')[-1].lower()
        if file_extension in ['pdf', 'doc', 'txt', 'png']:
            loaded_files.append(file)
        else:
            raise ValueError(f"Unsupported file format: {file_extension}")

    return loaded_files
